import React from "react";
import styles from "./cart-wrapper.module.css";
import TableHeading from "../table-heading";
import CartItem from "../cart-item";
import CartSubtotal from "../cart-subtotal";
import Button from "../../button";

// Import 'useAppSelector' and 'RootState'
import { RootState } from "../../../app/store";
import { useAppSelector } from "../../../app/hooks";
import { useSelector } from "react-redux";
import { getCartSelector } from "../../../app/cartSlice";

const CartWrapper = () => {
  // Get the cart items from the Redux store
  const cartItems = useSelector(getCartSelector);

  return (
    <div className={styles.cart_wrapper}>
      <div className="container">
        <div className="cart_top">
          <TableHeading
            col1="Product"
            col2="Price"
            col3="Quantity"
            col4="Total"
          />
        </div>
        <div className="cart_body">
          {cartItems.map((cartItem) => (
            <CartItem
              key={cartItem.id}
              product={{
                id: cartItem.id,
                img: cartItem.img,
                name: cartItem.name,
                price: cartItem.price,
              }}
            />
          ))}
        </div>
        <div className={styles.cart_bottom}>
          <CartSubtotal
            title="Sub-total"
            price={9.99}
            VAT="Tax and shipping cost will be calculated later"
          />
          <Button text="Check-out" to="/checkout" />
        </div>
      </div>
    </div>
  );
};

export default CartWrapper;



